import iostream

void enqueue(vector<int>& queue, int element) {
    queue.push_back(element);
}

void solve() {
    vector<int> queue = {1, 2, 3, 4, 5};
    enqueue(queue, 10);
    enqueue(queue, 20);
    for (int i : queue) {
        cout << i << ' ';
    }
    cout << endl;
}

int main() {
    solve();
    return 0;
}
